private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // --- Declare values ---
decimal hatchPer = 0;
decimal fertPer = 0;

// --- Accumulators for totals ---
decimal totalReportHatchPer = 0;
decimal totalReportFertPer = 0;

// --- HatchPer ---
if (GetCurrentColumnValue("HatchPer") != null)
    hatchPer = Convert.ToDecimal(GetCurrentColumnValue("HatchPer"));
    totalReportHatchPer += hatchPer;

// --- FertPer ---
if (GetCurrentColumnValue("FertPer") != null)
    fertPer = Convert.ToDecimal(GetCurrentColumnValue("FertPer"));
    totalReportFertPer += fertPer;

// --- Equation (row level %) ---
decimal percentage = 0;
if (fertPer != 0)
    percentage = (hatchPer * 100m) / fertPer;

// --- Total percentage ---
if (totalReportFertPer != 0)
    TotalPercentageHatchPer = (totalReportHatchPer * 100m) / totalReportFertPer;

// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level %

}

